//! Shared proto types + typed Temporal client for the job-queue demo.
//!
//! All concrete proto packages live as submodules generated by `buf generate`
//! into `src/gen/`. The typed Temporal client emitted by
//! `protoc-gen-rust-temporal` lands alongside them and references the proto
//! types through `crate::<package>::*`.
//!
//! Run `just gen` (or `buf generate` from `proto/`) to regenerate.

#![allow(clippy::all)]

pub use temporal_proto_runtime_bridge as temporal_runtime;

// Generated proto types and temporal clients are written to src/gen/.
// `buf generate` produces:
//   src/gen/jobs/v1/jobs.v1.rs            (prost types — file name is package-derived)
//   src/gen/jobs/v1/jobs_temporal.rs      (this plugin — file name is source-path-derived)
//   src/gen/temporal/v1/temporal.v1.rs    (annotation proto types — unused)
pub mod jobs {
    pub mod v1 {
        include!(concat!(
            env!("CARGO_MANIFEST_DIR"),
            "/src/gen/jobs/v1/jobs.v1.rs"
        ));
    }
}

// The plugin-emitted file declares `pub mod jobs_v1_job_service_temporal { ... }`
// at the top level; include! brings that module into the crate root.
include!(concat!(
    env!("CARGO_MANIFEST_DIR"),
    "/src/gen/jobs/v1/jobs_temporal.rs"
));

pub use temporal_proto_runtime::{TemporalProtoMessage, TypedProtoMessage};
